CREATE VIEW bi.v_dashboard_monthly AS
 SELECT (date_trunc('month'::text, (day)::timestamp with time zone))::date AS month_start,
    source,
    platform,
    campaign_key,
    campaign_name,
    provider_account_id,
    provider_account_name,
    currency_code,
    (sum(spend))::numeric(18,6) AS spend,
    (sum(clicks))::bigint AS clicks,
    (sum(impressions))::bigint AS impressions,
    (sum(reach))::bigint AS reach,
    (sum(conversions_api))::numeric(18,4) AS conversions_api,
    (sum(events_count))::bigint AS events_count,
    (sum(conversions_web))::bigint AS conversions_web,
    (sum(leads_new_count))::bigint AS leads_new_count,
    (sum(leads_touch_count))::bigint AS leads_touch_count,
    max(leads_target) AS leads_target,
    (max(lead_share_pct))::numeric(5,2) AS lead_share_pct,
    max(sales_target) AS sales_target,
    (max(conversion_rate_target))::numeric(5,2) AS conversion_rate_target,
        CASE
            WHEN (sum(clicks) > (0)::numeric) THEN round((sum(spend) / NULLIF(sum(clicks), (0)::numeric)), 4)
            ELSE NULL::numeric
        END AS cpc,
        CASE
            WHEN (sum(leads_new_count) > (0)::numeric) THEN round((sum(spend) / NULLIF(sum(leads_new_count), (0)::numeric)), 4)
            ELSE NULL::numeric
        END AS cpl,
        CASE
            WHEN (sum(conversions_web) > (0)::numeric) THEN round((sum(spend) / NULLIF(sum(conversions_web), (0)::numeric)), 4)
            ELSE NULL::numeric
        END AS cpa,
        CASE
            WHEN (max(leads_target) > 0) THEN round(((sum(leads_new_count) / (NULLIF(max(leads_target), 0))::numeric) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS lead_completion_pct,
        CASE
            WHEN (max(sales_target) > 0) THEN round(((sum(conversions_web) / (NULLIF(max(sales_target), 0))::numeric) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS sales_completion_pct
   FROM bi.v_dashboard_daily
  GROUP BY ((date_trunc('month'::text, (day)::timestamp with time zone))::date), source, platform, campaign_key, campaign_name, provider_account_id, provider_account_name, currency_code;


